# IT Portal - single-file installer.
#
# WHO RUNS THIS: an IT admin, once per machine, with administrator rights
# (elevated PowerShell / "Run as administrator", or via your remote management
# tool of choice). It installs the launcher + icon machine-wide and creates a
# shortcut on the shared "Public" desktop, so it shows up for EVERY user who
# logs into that machine afterward - a regular (non-admin) employee never
# needs to do anything but double-click the resulting "IT Portal" icon.
#
# HOW TO RUN: right-click this file -> "Run with PowerShell" (as administrator),
# or from an elevated PowerShell prompt:
#   powershell.exe -ExecutionPolicy Bypass -File Install-ITPortal.ps1
#
# This file is self-contained - the launcher script and the desktop icon are
# both embedded below, nothing else needs to be downloaded or copied alongside
# it.
#
# To uninstall, remove "C:\ProgramData\ITPortal" and the
# "IT Portal.lnk" shortcut from the Public desktop.

#Requires -RunAsAdministrator
$ErrorActionPreference = 'Stop'

$installDir = Join-Path $env:ProgramData 'ITPortal'
New-Item -ItemType Directory -Path $installDir -Force | Out-Null

# ── Embedded launcher (identical to deployment/launch-it-portal.vbs) ──────
# Reads the signed-in user's UPN (whoami /upn - no admin rights needed at
# *launch* time) and opens Microsoft Edge in app mode (no address bar) with
# the email passed as a URL fragment.
$launcherContent = @'
' IT Portal launcher.
' Reads the signed-in user's UPN (whoami /upn - no admin rights needed) and opens
' Microsoft Edge in app mode (no address bar) with the email passed as a URL
' fragment, e.g. https://it.ramilevystock.com/index.html#email=user@domain.co.il
'
' Runs silently (no console flash) because it's a .vbs, not a .bat.

Option Explicit

Dim PORTAL_BASE_URL
PORTAL_BASE_URL = "https://it.ramilevystock.com/index.html"

Dim shell, exec, upn, portalUrl

Set shell = CreateObject("WScript.Shell")
Set exec = shell.Exec("%comspec% /c whoami /upn")

Do While exec.Status = 0
    WScript.Sleep 50
Loop

upn = Trim(LCase(exec.StdOut.ReadAll()))

portalUrl = PORTAL_BASE_URL & "#email=" & upn

' Relies on Edge's "App Paths" registry entry so a full install path isn't needed.
shell.Run "msedge.exe --app=""" & portalUrl & """", 1, False
'@

Set-Content -Path (Join-Path $installDir 'launch-it-portal.vbs') -Value $launcherContent -Encoding ASCII

# ── Embedded icon (base64-encoded .ico, generated from the company logo) ──
$iconBase64 = @'

'@

$iconBytes = [Convert]::FromBase64String($iconBase64)
[IO.File]::WriteAllBytes((Join-Path $installDir 'it-portal.ico'), $iconBytes)

# ── Shortcut on the shared Public desktop (visible to every user) ─────────
$publicDesktop = [Environment]::GetFolderPath('CommonDesktopDirectory')
$shortcutPath = Join-Path $publicDesktop 'IT Portal.lnk'

$shell2 = New-Object -ComObject WScript.Shell
$shortcut = $shell2.CreateShortcut($shortcutPath)
$shortcut.TargetPath = Join-Path $env:WINDIR 'System32\wscript.exe'
$shortcut.Arguments = '"' + (Join-Path $installDir 'launch-it-portal.vbs') + '"'
$shortcut.IconLocation = Join-Path $installDir 'it-portal.ico'
$shortcut.Description = 'IT Portal'
$shortcut.WorkingDirectory = $installDir
$shortcut.Save()

Write-Output "IT Portal installed. Shortcut created at: $shortcutPath"
